qss:
QWidget { background: #140d1f; color: #f3e9ff; font-family: Segoe UI, Arial, sans-serif; font-size: 10pt; }
QMainWindow, QDialog { background: #140d1f; }
QGroupBox { background: #21152f; border: 1px solid #65428c; border-radius: 8px; margin-top: 12px; padding: 10px; font-weight: bold; }
QGroupBox::title { subcontrol-origin: margin; left: 12px; padding: 0 4px; color: #a855f7; }
QTabWidget::pane { border: 1px solid #65428c; background: #21152f; }
QTabBar::tab { background: #10091a; color: #f3e9ff; padding: 8px 14px; border: 1px solid #65428c; border-bottom: none; min-width: 100px; }
QTabBar::tab:selected { background: #7e22ce; color: #ffffff; font-weight: bold; }
QTabBar::tab:hover { background: #3b2259; color: #ffffff; }
QPushButton { background: #3b2259; color: #ffffff; border: 1px solid #a855f7; border-radius: 6px; padding: 7px 12px; font-weight: 600; }
QPushButton:hover { background: #a855f7; color: #ffffff; }
QPushButton:disabled { background: #66517d; color: #10091a; border-color: #65428c; }
QLineEdit, QTextEdit, QTextBrowser, QPlainTextEdit, QComboBox, QSpinBox, QDoubleSpinBox { background: #10091a; color: #f3e9ff; border: 1px solid #65428c; border-radius: 5px; padding: 5px; selection-background-color: #a855f7; selection-color: #ffffff; }
QComboBox QAbstractItemView { background: #10091a; color: #f3e9ff; selection-background-color: #a855f7; selection-color: #ffffff; border: 1px solid #65428c; }
QTableWidget { background: #10091a; alternate-background-color: #21152f; color: #f3e9ff; gridline-color: #65428c; selection-background-color: #a855f7; selection-color: #ffffff; }
QHeaderView::section { background: #7e22ce; color: #ffffff; padding: 6px; border: 1px solid #65428c; font-weight: bold; }
QScrollBar:vertical { background: #21152f; width: 14px; }
QScrollBar::handle:vertical { background: #a855f7; border-radius: 6px; min-height: 24px; }
QScrollBar:horizontal { background: #21152f; height: 14px; }
QScrollBar::handle:horizontal { background: #a855f7; border-radius: 6px; min-width: 24px; }
QCheckBox { spacing: 6px; }
QLabel { color: #f3e9ff; }
